scwin._getCommonParam = function () {
    return {
        kcomcd: $c.str.trim(scwin.hd_kcomcd),
        iogb: $c.str.trim(scwin.hd_mhio),
        mhno: $c.str.trim(cnd_lc_mhno.getValue()),
        blno: $c.str.trim(cnd_ed_hhblno.getValue()),
        mblno: $c.str.trim(cnd_ed_mhmblno.getValue())
    };
};

scwin._openMenu = function (title, path, menuId, param) {
    $c.win.openMenu(title, path, menuId, param || {},{openAction: "exist"});
};

scwin.f_openPgm = function (name) {
    var commonParam = scwin._getCommonParam();

    switch (name) {
        case "Partner":
            scwin._openMenu(
                "Partner Invoice",
                "/ui/il/acc/acpar/ac_104_01_01b.xml",
                "ac_104_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: "",
                    mblno: commonParam.mblno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "Profit":
            scwin._openMenu(
                "Booking Sheet",
                "/ui/il/pfm/pfbs/pe_101_01_01b.xml",
                "pe_101_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: commonParam.blno,
                    mblno: "",
                    mhno: commonParam.mhno
                }
            );
            break;
        case "paymentINV":
            scwin._openMenu(
                "Payment Invoice",
                "/ui/il/acc/acpay/ac_106_01_01b.xml",
                "ac_106_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    seaair: "S",
                    iogb: commonParam.iogb,
                    blno: "",
                    mblno: commonParam.mblno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "MasterFreight":
            scwin._openMenu(
                "Import Master B/L Freight",
                "/ui/il/seainb/sibl/se_202_01_02b.xml",
                "se_202_01_02b.xml",
                {
                    linkcheck: "6",
                    kcomcd: commonParam.kcomcd,
                    blno: commonParam.blno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "HouseBLFind":
            scwin._openMenu(
                "House B/L Search",
                "/ui/il/seaout/sobl/se_105_01_02b.xml",
                "se_105_01_02b.xml",
                { hhio: commonParam.iogb }
            );
            break;
        case "SRPrint":
            scwin._openMenu(
                "Shipping Request",
                "/ui/il/seaout/soth/se_109_01_01b.xml",
                "se_109_01_01b.xml",
                {
                    kcomcd: commonParam.kcomcd,
                    blno: commonParam.blno,
                    mhno: commonParam.mhno
                }
            );
            break;
        case "MasterBLFind":
            scwin._openMenu(
                "Master B/L Search",
                "/ui/il/seaout/sobl/se_106_01_02b.xml",
                "se_106_01_02b.xml",
                { mhio: commonParam.iogb }
            );
            break;
    }
};

